```{ojs}
//| echo: false
deg = Math.PI / 180
v_raw = [2, 1]
v_norm_raw = Math.sqrt(v_raw[0]**2 + v_raw[1]**2)
v = [v_raw[0] / v_norm_raw, v_raw[1] / v_norm_raw]
phi = Math.atan2(v[1], v[0])
u = [Math.cos(phi + theta * deg), Math.sin(phi + theta * deg)]
dot = (a, b) => a[0]*b[0] + a[1]*b[1]
norm = a => Math.sqrt(dot(a, a))
k = dot(u, v)
proj = [k * v[0], k * v[1]]
w = [c_w * v[0], c_w * v[1]]
perp = [-v[1], v[0]]
side = dot(perp, [u[0] - proj[0], u[1] - proj[1]]) >= 0 ? -1 : 1
label_offset = 0.22
proj_label = [proj[0] + side * label_offset * perp[0], proj[1] + side * label_offset * perp[1]]
w_label = [w[0] + side * label_offset * perp[0], w[1] + side * label_offset * perp[1]]
res_norm = Math.hypot(u[0] - proj[0], u[1] - proj[1])
hyp_norm = Math.hypot(u[0] - w[0], u[1] - w[1])
lim = 1.6

stats = md`**‖u − proj_v(u)‖** = ${res_norm.toFixed(3)}  ·  **‖u − w‖** = ${hyp_norm.toFixed(3)}`
```

