//| echo: false
viewof theta_u_cov = Inputs.range([0, 360], {value: 45, step: 1, label: "Angle of u (°)"})
viewof rho = Inputs.range([-0.99, 0.99], {value: 0.9, step: 0.01, label: "Correlation ρ"})
```

```{ojs}
//| echo: false
// regenerate point cloud with same seed whenever rho changes
points = {
  let s = 1337;
  const rand = () => {
    s |= 0; s = (s + 0x6D2B79F5) | 0;
    let t = s;
    t = Math.imul(t ^ (t >>> 15), t | 1);
    t ^= t + Math.imul(t ^ (t >>> 7), t | 61);
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
  const randn = () => {
    let r1 = 0, r2 = 0;
    while (r1 === 0) r1 = rand();
    while (r2 === 0) r2 = rand();
    return Math.sqrt(-2 * Math.log(r1)) * Math.cos(2 * Math.PI * r2);
  };
  // Cholesky of [[1, rho], [rho, 1]] => L = [[1, 0], [rho, sqrt(1 - rho^2)]]
  const L22 = Math.sqrt(1 - rho * rho);
  return Array.from({length: 10}, () => {
    const z1 = randn(), z2 = randn();
    return [z1, rho * z1 + L22 * z2];
  });
}
```

```{ojs}
//| echo: false
