  const u_cov = [Math.cos(theta_u_cov * deg_cov), Math.sin(theta_u_cov * deg_cov)];
  const projections = points.map(p => {
    const k = u_cov[0]*p[0] + u_cov[1]*p[1];
    return [k * p[0], k * p[1]];
  });
  const on_u = projections.map(P => {
    const k = P[0]*u_cov[0] + P[1]*u_cov[1];
    return [k * u_cov[0], k * u_cov[1]];
  });
  const lim_cov = 3.2;
  const big = lim_cov * 3;
  return Plot.plot({
    width: 600,
    height: 600,
